{
  "children": [
    {
      "name": "IngestData",
      "global_vars": [
        {
          "name": "raw_data",
          "type": "memory",
          "access": "read_write",
          "description": "Store raw ingested data"
        }
      ],
      "data_operations": [
        {
          "operation": "write",
          "target": "raw_data",
          "description": "Write ingested data to raw_data store"
        }
      ],
      "error_handling": [
        {
          "condition": "input missing or invalid source",
          "action": "return error in ingestion_result with success=false"
        },
        {
          "condition": "data read failure",
          "action": "log error and return failure"
        }
      ],
      "logging": [
        {
          "event": "ingestion_start",
          "level": "info",
          "message": "Starting data ingestion"
        },
        {
          "event": "ingestion_complete",
          "level": "info",
          "message": "Data ingestion completed with {records_count} records"
        },
        {
          "event": "ingestion_error",
          "level": "error",
          "message": "Data ingestion failed: {error_details}"
        }
      ],
      "resource_limits": {
        "max_memory_mb": 256,
        "max_time_seconds": 30
      }
    },
    {
      "name": "TransformData",
      "global_vars": [
        {
          "name": "raw_data",
          "type": "memory",
          "access": "read_write",
          "description": "Read raw data for transformation"
        },
        {
          "name": "processed_data",
          "type": "memory",
          "access": "read_write",
          "description": "Write transformed data"
        }
      ],
      "data_operations": [
        {
          "operation": "read",
          "target": "raw_data",
          "description": "Read raw data for transformation"
        },
        {
          "operation": "write",
          "target": "processed_data",
          "description": "Write transformed data to processed_data store"
        }
      ],
      "error_handling": [
        {
          "condition": "raw_data empty or unavailable",
          "action": "return error in transformation_result with success=false"
        },
        {
          "condition": "transformation rule failure",
          "action": "log error and skip problematic records"
        }
      ],
      "logging": [
        {
          "event": "transform_start",
          "level": "info",
          "message": "Starting data transformation"
        },
        {
          "event": "transform_complete",
          "level": "info",
          "message": "Data transformation completed with {records_transformed} records"
        },
        {
          "event": "transform_error",
          "level": "error",
          "message": "Data transformation error: {error_details}"
        }
      ],
      "resource_limits": {
        "max_memory_mb": 512,
        "max_time_seconds": 60
      }
    },
    {
      "name": "ValidateQuality",
      "global_vars": [
        {
          "name": "processed_data",
          "type": "memory",
          "access": "read_write",
          "description": "Read processed data for validation"
        }
      ],
      "data_operations": [
        {
          "operation": "read",
          "target": "processed_data",
          "description": "Read processed data for validation"
        }
      ],
      "error_handling": [
        {
          "condition": "processed_data empty or unavailable",
          "action": "return error in validation_result with success=false"
        },
        {
          "condition": "validation rule failure",
          "action": "log error and mark record as invalid"
        }
      ],
      "logging": [
        {
          "event": "validation_start",
          "level": "info",
          "message": "Starting data validation"
        },
        {
          "event": "validation_complete",
          "level": "info",
          "message": "Validation completed: {valid_count} valid, {invalid_count} invalid"
        },
        {
          "event": "validation_error",
          "level": "error",
          "message": "Validation error: {error_details}"
        }
      ],
      "resource_limits": {
        "max_memory_mb": 256,
        "max_time_seconds": 30
      }
    },
    {
      "name": "ExportResults",
      "global_vars": [
        {
          "name": "processed_data",
          "type": "memory",
          "access": "read_write",
          "description": "Read valid records for export"
        }
      ],
      "data_operations": [
        {
          "operation": "read",
          "target": "processed_data",
          "description": "Read valid records from processed_data for export"
        }
      ],
      "error_handling": [
        {
          "condition": "no valid records to export",
          "action": "return output with empty data and success=true"
        },
        {
          "condition": "output formatting failure",
          "action": "log error and return failure"
        }
      ],
      "logging": [
        {
          "event": "export_start",
          "level": "info",
          "message": "Starting data export"
        },
        {
          "event": "export_complete",
          "level": "info",
          "message": "Export completed with {records_exported} records"
        },
        {
          "event": "export_error",
          "level": "error",
          "message": "Export error: {error_details}"
        }
      ],
      "resource_limits": {
        "max_memory_mb": 128,
        "max_time_seconds": 15
      }
    }
  ]
}
